const VENDOR_CODES = ['RDG','MMI','DNR','HBO','FOR','OBO','BMW','CDR','VVM','ACD','SOB','JIR','TRM','BAF','MYO','DWK','ALA','VAR','BBR','KPA','RIG','NWW'];
const FIBER_NAME_TO_CODE = { 'FF Nylon': 'FFN', 'E Nylon': 'EN', 'FF Cotton': 'FFC', 'Blackwing': 'BW' };

const body = $('Webhook1').item.json.body || $('Webhook1').item.json;
const existing = $json.records || [];
const version = existing.length + 1;
const hasExistingPreview = existing.some(r => r.fields && r.fields.Is_Preview);
const shouldBePreview = !hasExistingPreview;

function slugify(name) {
  return (name || '').toString().toLowerCase().trim().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '');
}
function fiberCode(fiberType) {
  if (FIBER_NAME_TO_CODE[fiberType]) return FIBER_NAME_TO_CODE[fiberType];
  return (fiberType || '').toString().toUpperCase().replace(/[^A-Z]/g, '').slice(0, 4) || 'GEN';
}
function vendorCode(skuBase, scope) {
  if (!skuBase || !/reserv/i.test(scope || '')) return null;
  const parts = skuBase.toString().split('_');
  const last = (parts[parts.length - 1] || '').toUpperCase();
  return VENDOR_CODES.includes(last) ? last : null;
}

const slug = slugify(body.colorway_name);
const fc = fiberCode(body.fiber_type);
const vendor = vendorCode(body.sku_base, body.recipe_scope);
const vendorSuffix = vendor ? `_${vendor}` : '';

const destFilename = `${body.colorway_name.replace(/\s+/g, '_')}_${version}_${fc}${vendorSuffix}${body.ext}`;
const destPath = `Squirrely Stash/product-photos/lots/${destFilename}`;
const proxyUrl = `https://squirrelystash.app.n8n.cloud/webhook/photo2?path=${encodeURIComponent(destPath)}`;

return {
  json: {
    source_path: body.source_path,
    dest_path: destPath,
    dest_filename: destFilename,
    proxy_url: proxyUrl,
    colorway_name: body.colorway_name,
    fiber_type: body.fiber_type,
    recipe_id: body.recipe_id,
    note_text: body.note_text || '',
    is_preview: shouldBePreview,
  }
};
